SELECT AVG(cost_per_click) AS avg_cost_per_click, SUM(spent) AS total_spent
FROM ad_performance
WHERE ad_id = 0 AND platform = 'Facebook';

SELECT AVG(file_size) AS average_file_size, MAX(file_size) AS max_file_size
FROM ad_content
WHERE platform = 'Facebook';

SELECT amount
FROM ad_spending
WHERE ad_id = 1 AND date = '2017-08-25';
